// ========================================
// WF2 v2 - VALIDATE & EXTRACT FORM DATA
// ========================================

const input = $input.first().json;
console.log('[WF2] Received webhook:', JSON.stringify(input, null, 2));

// Extract data from webhook payload
const formData = input.body?.data || input.data || {};
const meta = {
  formResponseId: input.body?.formResponseId || input.formResponseId || '',
  timestamp: input.body?.timestamp || input.timestamp || new Date().toISOString(),
  respondentEmail: input.body?.respondentEmail || input.respondentEmail || 'unknown',
  editResponseUrl: input.body?.editResponseUrl || input.editResponseUrl || ''
};

// Extract fields
const clarificationId = formData.clarificationId || '';
const nguonChiDao = formData.nguonChiDao || 'CEO';
const ngayNhanChiDao = formData.ngayNhanChiDao || '';
const noiDungGoc = formData.noiDungGoc || '';
const dauMoiT1 = formData.dauMoiT1 || '';
const t2NhiemVu = formData.t2NhiemVu || '';
const t3ChiTieu = formData.t3ChiTieu || '';
const t4ThoiHan = formData.t4ThoiHan || '';
const ghiChu = formData.ghiChu || '';
const xacNhan = formData.xacNhan || false;

// Validate required fields
const errors = [];
if (!clarificationId) errors.push('Thiếu Mã Clarification');
if (!t2NhiemVu) errors.push('Thiếu T2 - Nhiệm vụ');
if (!t3ChiTieu) errors.push('Thiếu T3 - Chỉ tiêu');
if (!t4ThoiHan) errors.push('Thiếu T4 - Thời hạn');
if (!xacNhan) errors.push('Chưa xác nhận nhận chỉ đạo');

const isValid = errors.length === 0;
const has4T = Boolean(dauMoiT1 && t2NhiemVu && t3ChiTieu && t4ThoiHan);

console.log(`[WF2] Clarification: ${clarificationId}`);
console.log(`[WF2] Valid: ${isValid} | Has 4T: ${has4T}`);
if (!isValid) console.log(`[WF2] Errors: ${errors.join(', ')}`);

return {
  // Meta
  ...meta,

  // Form data
  clarificationId,
  nguonChiDao,
  ngayNhanChiDao,
  noiDungGoc,
  dauMoiT1,
  t2NhiemVu,
  t3ChiTieu,
  t4ThoiHan,
  ghiChu,
  xacNhan,

  // Validation
  isValid,
  has4T,
  errors,

  // For Task creation
  taskTitle: `${dauMoiT1 ? dauMoiT1 + ': ' : ''}${noiDungGoc.substring(0, 80)}${noiDungGoc.length > 80 ? '...' : ''}`,
  today: new Date().toISOString().split('T')[0]
};

